const WebSocket = require('ws');
const http = require('http');

const PORT = process.env.PORT || 8080;

const server = http.createServer();
const wss = new WebSocket.Server({ server });

const game = {
  players: new Map(),
  units: new Map(),
  buildings: new Map(),
  nextEntityId: 1,
  tickRate: 20,
  startedAt: Date.now()
};

function makeId() {
  return String(game.nextEntityId++);
}

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function distance(a, b) {
  const dx = (a.x - b.x);
  const dy = (a.y - b.y);
  return Math.sqrt(dx * dx + dy * dy);
}

function broadcast(payload) {
  const data = JSON.stringify(payload);
  for (const client of wss.clients) {
    if (client.readyState === WebSocket.OPEN) client.send(data);
  }
}

function send(ws, payload) {
  if (ws.readyState === WebSocket.OPEN) ws.send(JSON.stringify(payload));
}

function getPlayerByWs(ws) {
  return game.players.get(ws);
}

function ensurePlayer(ws) {
  let player = game.players.get(ws);
  if (!player) {
    player = {
      id: makeId(),
      ws,
      name: `Player-${Math.floor(Math.random() * 10000)}`,
      resources: 500,
      units: new Set(),
      buildings: new Set(),
      color: `hsl(${Math.floor(Math.random() * 360)}, 80%, 60%)`
    };
    game.players.set(ws, player);
    send(ws, { type: 'welcome', playerId: player.id, name: player.name, color: player.color });
    broadcastState();
  }
  return player;
}

function createUnit(ownerId, x, y, type = 'soldier') {
  const unit = {
    id: makeId(),
    ownerId,
    type,
    x,
    y,
    hp: type === 'worker' ? 50 : 100,
    maxHp: type === 'worker' ? 50 : 100,
    speed: type === 'worker' ? 1.2 : 1.0,
    attackDamage: type === 'worker' ? 5 : 10,
    attackRange: type === 'worker' ? 1.0 : 1.5,
    target: null,
    moveTarget: null,
    cooldown: 0
  };
  game.units.set(unit.id, unit);
  const owner = [...game.players.values()].find(p => p.id === ownerId);
  if (owner) owner.units.add(unit.id);
  return unit;
}

function createBuilding(ownerId, x, y, type = 'base') {
  const building = {
    id: makeId(),
    ownerId,
    type,
    x,
    y,
    hp: 500,
    maxHp: 500
  };
  game.buildings.set(building.id, building);
  const owner = [...game.players.values()].find(p => p.id === ownerId);
  if (owner) owner.buildings.add(building.id);
  return building;
}

function removeUnit(unitId) {
  const unit = game.units.get(unitId);
  if (!unit) return;
  const owner = [...game.players.values()].find(p => p.id === unit.ownerId);
  if (owner) owner.units.delete(unitId);
  game.units.delete(unitId);
}

function removeBuilding(buildingId) {
  const building = game.buildings.get(buildingId);
  if (!building) return;
  const owner = [...game.players.values()].find(p => p.id === building.ownerId);
  if (owner) owner.buildings.delete(buildingId);
  game.buildings.delete(buildingId);
}

function getEntityById(id) {
  return game.units.get(id) || game.buildings.get(id) || null;
}

function serializeState() {
  return {
    type: 'state',
    players: [...game.players.values()].map(p => ({
      id: p.id,
      name: p.name,
      resources: p.resources,
      color: p.color
    })),
    units: [...game.units.values()].map(u => ({
      id: u.id,
      ownerId: u.ownerId,
      type: u.type,
      x: u.x,
      y: u.y,
      hp: u.hp,
      maxHp: u.maxHp,
      target: u.target,
      moveTarget: u.moveTarget
    })),
    buildings: [...game.buildings.values()].map(b => ({
      id: b.id,
      ownerId: b.ownerId,
      type: b.type,
      x: b.x,
      y: b.y,
      hp: b.hp,
      maxHp: b.maxHp
    }))
  };
}

function broadcastState() {
  broadcast(serializeState());
}

function handleBuild(player, msg) {
  const { buildingType = 'base', x = 0, y = 0 } = msg;
  const cost = buildingType === 'base' ? 300 : 100;
  if (player.resources < cost) {
    send(player.ws, { type: 'error', message: 'Not enough resources' });
    return;
  }
  player.resources -= cost;
  createBuilding(player.id, clamp(x, 0, 1000), clamp(y, 0, 1000), buildingType);
  broadcastState();
}

function handleTrain(player, msg) {
  const { unitType = 'soldier', x = 0, y = 0 } = msg;
  const cost = unitType === 'worker' ? 50 : 100;
  if (player.resources < cost) {
    send(player.ws, { type: 'error', message: 'Not enough resources' });
    return;
  }
  player.resources -= cost;
  createUnit(player.id, clamp(x, 0, 1000), clamp(y, 0, 1000), unitType);
  broadcastState();
}

function handleMove(player, msg) {
  const { unitId, x = 0, y = 0 } = msg;
  const unit = game.units.get(unitId);
  if (!unit || unit.ownerId !== player.id) {
    send(player.ws, { type: 'error', message: 'Invalid unit' });
    return;
  }
  unit.moveTarget = { x: clamp(x, 0, 1000), y: clamp(y, 0, 1000) };
  unit.target = null;
  broadcastState();
}

function handleAttack(player, msg) {
  const { unitId, targetId } = msg;
  const unit = game.units.get(unitId);
  const target = getEntityById(targetId);
  if (!unit || unit.ownerId !== player.id || !target) {
    send(player.ws, { type: 'error', message: 'Invalid attack command' });
    return;
  }
  unit.target = targetId;
  unit.moveTarget = null;
  broadcastState();
}

function processCommands(player, msg) {
  if (!msg || typeof msg !== 'object') return;
  switch (msg.type) {
    case 'build':
      return handleBuild(player, msg);
    case 'train':
      return handleTrain(player, msg);
    case 'move':
      return handleMove(player, msg);
    case 'attack':
      return handleAttack(player, msg);
    case 'name':
      if (typeof msg.name === 'string' && msg.name.trim()) {
        player.name = msg.name.trim().slice(0, 24);
        broadcastState();
      }
      return;
    case 'ping':
      return send(player.ws, { type: 'pong', t: Date.now() });
    default:
      return send(player.ws, { type: 'error', message: 'Unknown command' });
  }
}

function updateGame() {
  for (const unit of game.units.values()) {
    if (unit.cooldown > 0) unit.cooldown -= 1;

    if (unit.moveTarget) {
      const dx = unit.moveTarget.x - unit.x;
      const dy = unit.moveTarget.y - unit.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 0.1) {
        unit.x = unit.moveTarget.x;
        unit.y = unit.moveTarget.y;
        unit.moveTarget = null;
      } else {
        const step = unit.speed;
        unit.x += (dx / dist) * Math.min(step, dist);
        unit.y += (dy / dist) * Math.min(step, dist);
      }
    }

    if (unit.target) {
      const target = getEntityById(unit.target);
      if (!target) {
        unit.target = null;
        continue;
      }
      const d = distance(unit, target);
      if (d <= unit.attackRange) {
        if (unit.cooldown <= 0) {
          target.hp -= unit.attackDamage;
          unit.cooldown = 10;
          if (target.hp <= 0) {
            if (game.units.has(target.id)) removeUnit(target.id);
            else if (game.buildings.has(target.id)) removeBuilding(target.id);
            unit.target = null;
          }
        }
      } else {
        const dx = target.x - unit.x;
        const dy = target.y - unit.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
        const step = unit.speed;
        unit.x += (dx / dist) * Math.min(step, dist);
        unit.y += (dy / dist) * Math.min(step, dist);
      }
    }
  }
}

setInterval(() => {
  updateGame();
  broadcastState();
}, 1000 / game.tickRate);

wss.on('connection', (ws) => {
  const player = ensurePlayer(ws);
  send(ws, { type: 'state', ...serializeState() });

  ws.on('message', (data) => {
    let msg;
    try {
      msg = JSON.parse(data.toString());
    } catch {
      send(ws, { type: 'error', message: 'Invalid JSON' });
      return;
    }
    processCommands(player, msg);
  });

  ws.on('close', () => {
    game.players.delete(ws);
  });
});

server.listen(PORT, () => {
  console.log(`RTS WebSocket server listening on ${PORT}`);
});